local LxBaseCtrl = require("LApp.controller.LxBaseCtrl")
---@class LxSuburbsCtrl:LxBaseCtrl
local LxSuburbsCtrl = classX("LxSuburbsCtrl", LxBaseCtrl)

function LxSuburbsCtrl:Initialize()
    LxBaseCtrl.Initialize(self)
end

function LxSuburbsCtrl:Dispose()
    LxBaseCtrl.Dispose(self)
end


function LxSuburbsCtrl:GetGameInletListByType(type)
    if not self._initGameInletTypeList then
        self._initGameInletTypeList = {}
    end
    local typeList = self._initGameInletTypeList[type]
    if not typeList then
        typeList = {}
        for k,v in pairs(GameTable.GameInletRef) do
            if v.type == type then
                table.insert(typeList,{
                    refId = k,
                    name = I18nText(v.name),
                    type = type,
                    sort = v.sort,
                    jumpId = v.jumpId,
                    combatType = v.combatType,
                    icon = v.icon,
                    text1 = I18nText(v.text1),
                    text2 = I18nText(v.text2),
                })
            end
        end
        table.sort(typeList,function(a,b) return a.sort < b.sort end)
        self._initGameInletTypeList[type] = typeList
    end
    return typeList
end




return LxSuburbsCtrl
